-- Amplia o "banco de treinos e dietas" pra dar ao algoritmo de seleção
-- (generatePlan/generateMealPlan em app-react/src/data/) candidatos reais
-- pra escolher, além do que o usuário já declara (objetivo/nível):
--
-- 1. Restrição alimentar: até aqui não existia nenhuma dimensão de dieta —
--    um usuário vegetariano recebia cardápio cheio de carne sem alternativa.
--    meal_templates ganha a coluna `restricao` (padrao/vegetariano/
--    low_carb) e a chave primária passa a ser composta (meta, restricao).
-- 2. Novo objetivo `resistencia` (condicionamento cardiovascular): os 5
--    objetivos existentes são todos focados em composição corporal/força;
--    nenhum cobre quem treina para corrida/resistência.
--
-- Ajuste de nível (iniciante/intermediario/avancado) continua sendo
-- calculado em tempo real por applyLevelAdjustment — nenhuma linha nova por
-- nível é gravada aqui, de propósito.

alter table public.meal_templates add column if not exists restricao text not null default 'padrao';

alter table public.meal_templates drop constraint if exists meal_templates_pkey;
alter table public.meal_templates add constraint meal_templates_pkey primary key (meta, restricao);

-- Novas dietas (variantes por restrição alimentar) e novo objetivo "resistência".
-- Ver comentário em app-react/src/data/mealTemplates.js e workoutTemplates.js.

insert into public.meal_templates (meta, restricao, meals) values ('massa', 'vegetariano', $mt$[{"horario":"07:30","nome":"☀️ Café da manhã","descricao":"4 ovos inteiros + 2 fatias de pão integral · 1 col. pasta de amendoim · 1 banana · Café preto","kcal":650,"proteina":34,"carboidrato":68,"gordura":26},{"horario":"10:30","nome":"🍏 Lanche da manhã","descricao":"1 scoop Whey (ou 200g iogurte grego) · 30g castanhas · 1 fruta","kcal":380,"proteina":32,"carboidrato":28,"gordura":17},{"horario":"13:00","nome":"🥗 Almoço","descricao":"200g tofu grelhado ou grão-de-bico cozido · 250g arroz integral · 150g batata-doce · Brócolis com azeite","kcal":850,"proteina":45,"carboidrato":120,"gordura":22},{"horario":"17:30","nome":"⚡ Pré-treino pesado","descricao":"150g queijo cottage · 2 fatias de pão integral · 1 banana · 500ml água","kcal":550,"proteina":42,"carboidrato":78,"gordura":8},{"horario":"19:30","nome":"☕ Pré-treino leve","descricao":"Café preto (sem açúcar) · 1 scoop Whey (opcional)","kcal":120,"proteina":24,"carboidrato":3,"gordura":2},{"horario":"20:00","nome":"🏋️ Treino","descricao":"Beba **500ml a 1L** de água durante o treino","kcal":0,"proteina":0,"carboidrato":0,"gordura":0},{"horario":"21:15","nome":"🍽️ Pós-treino / Jantar","descricao":"200g lentilha cozida + 100g tofu grelhado · 250g arroz branco · Salada verde com azeite","kcal":780,"proteina":40,"carboidrato":110,"gordura":18},{"horario":"23:30","nome":"🥛 Ceia (opcional)","descricao":"Se bater fome: 2 ovos cozidos ou 1 scoop caseína com água","kcal":140,"proteina":12,"carboidrato":1,"gordura":10}]$mt$::jsonb) on conflict (meta, restricao) do nothing;
